import { Link } from 'react-router-dom';
import { useState } from 'react';

const categories = ['Technology', 'Health', 'Education', 'Environment', 'Art', 'Social Impact'];

/* ── Trending Projects data ── */
const PROJECTS = [
  {
    id: 1,
    title: 'NeuroSync Headband',
    creator: 'Aria Patel',
    category: 'Health Tech',
    desc: 'EEG-powered focus optimizer that learns your brain patterns and blocks distractions in real-time.',
    raised: 68400,
    goal: 80000,
    backers: 941,
    daysLeft: 9,
    aiScore: 93,
    accentA: '#00d4aa',
    accentB: '#0891b2',
    pattern: 'circles',
    avatarColors: ['#00d4aa', '#0891b2', '#6366f1'],
  },
  {
    id: 2,
    title: 'SolarPack Pro',
    creator: 'Marcus Webb',
    category: 'CleanTech',
    desc: 'Ultra-thin flexible solar panels woven into a 30L backpack. Charge anything, anywhere, silently.',
    raised: 124500,
    goal: 150000,
    backers: 1832,
    daysLeft: 14,
    aiScore: 88,
    accentA: '#f59e0b',
    accentB: '#ef4444',
    pattern: 'grid',
    avatarColors: ['#f59e0b', '#ef4444', '#00d4aa'],
  },
  {
    id: 3,
    title: 'EduBot Classrooms',
    creator: 'Yemi Okafor',
    category: 'EdTech',
    desc: 'Adaptive AI tutor that reshapes lesson plans every 60 seconds based on live student comprehension.',
    raised: 39200,
    goal: 60000,
    backers: 578,
    daysLeft: 21,
    aiScore: 91,
    accentA: '#8b5cf6',
    accentB: '#ec4899',
    pattern: 'dots',
    avatarColors: ['#8b5cf6', '#ec4899', '#f59e0b'],
  },
];

/* ── SVG pattern visual card headers ── */
function PatternBg({ pattern, accentA, accentB, id }) {
  if (pattern === 'circles') return (
    <svg width="100%" height="100%" xmlns="http://www.w3.org/2000/svg" style={{ position: 'absolute', inset: 0 }}>
      <defs>
        <radialGradient id={`rg${id}`} cx="30%" cy="40%" r="60%">
          <stop offset="0%" stopColor={accentA} stopOpacity="0.3" />
          <stop offset="100%" stopColor={accentB} stopOpacity="0.04" />
        </radialGradient>
      </defs>
      <rect width="100%" height="100%" fill={`url(#rg${id})`} />
      {[70, 115, 160, 55, 200].map((r, i) => (
        <circle key={i} cx={`${12 + i * 19}%`} cy={`${18 + (i % 3) * 26}%`} r={r}
          fill="none" stroke={accentA} strokeOpacity="0.1" strokeWidth="1" />
      ))}
    </svg>
  );
  if (pattern === 'grid') return (
    <svg width="100%" height="100%" xmlns="http://www.w3.org/2000/svg" style={{ position: 'absolute', inset: 0 }}>
      <defs>
        <linearGradient id={`lg${id}`} x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor={accentA} stopOpacity="0.22" />
          <stop offset="100%" stopColor={accentB} stopOpacity="0.08" />
        </linearGradient>
        <pattern id={`gp${id}`} width="26" height="26" patternUnits="userSpaceOnUse">
          <path d="M 26 0 L 0 0 0 26" fill="none" stroke={accentA} strokeOpacity="0.15" strokeWidth="0.5" />
        </pattern>
      </defs>
      <rect width="100%" height="100%" fill={`url(#lg${id})`} />
      <rect width="100%" height="100%" fill={`url(#gp${id})`} />
    </svg>
  );
  return (
    <svg width="100%" height="100%" xmlns="http://www.w3.org/2000/svg" style={{ position: 'absolute', inset: 0 }}>
      <defs>
        <radialGradient id={`dg${id}`} cx="70%" cy="30%" r="70%">
          <stop offset="0%" stopColor={accentA} stopOpacity="0.28" />
          <stop offset="100%" stopColor={accentB} stopOpacity="0.06" />
        </radialGradient>
      </defs>
      <rect width="100%" height="100%" fill={`url(#dg${id})`} />
      {Array.from({ length: 25 }).map((_, i) => (
        <circle key={i} cx={`${(i % 5) * 22 + 7}%`} cy={`${Math.floor(i / 5) * 22 + 8}%`}
          r="2.2" fill={accentA} fillOpacity="0.18" />
      ))}
    </svg>
  );
}

/* ── Single project card ── */
function ProjectCard({ project, index }) {
  const [hovered, setHovered] = useState(false);
  const pct = Math.round((project.raised / project.goal) * 100);
  const initials = project.title.split(' ').map(w => w[0]).join('');

  return (
    <div
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        background: '#0f1623',
        border: `1px solid ${hovered ? project.accentA + '50' : '#1f2937'}`,
        borderRadius: 20,
        overflow: 'hidden',
        display: 'flex',
        flexDirection: 'column',
        transition: 'border-color 0.3s, transform 0.3s, box-shadow 0.3s',
        transform: hovered ? 'translateY(-7px)' : 'translateY(0)',
        boxShadow: hovered ? `0 24px 60px ${project.accentA}1a` : '0 4px 24px #00000044',
      }}
    >
      {/* Visual header */}
      <div style={{ position: 'relative', height: 148, background: '#060810', overflow: 'hidden', flexShrink: 0 }}>
        <PatternBg pattern={project.pattern} accentA={project.accentA} accentB={project.accentB} id={project.id} />
        {/* Big monogram watermark */}
        <div style={{
          position: 'absolute', inset: 0,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          pointerEvents: 'none',
        }}>
          <span style={{
            fontFamily: 'Syne, sans-serif', fontSize: 72, fontWeight: 900,
            color: project.accentA, opacity: 0.12, letterSpacing: '-6px', userSelect: 'none',
          }}>
            {initials}
          </span>
        </div>
        {/* AI Score */}
        <div style={{
          position: 'absolute', top: 12, right: 12,
          background: 'rgba(0,0,0,0.65)', backdropFilter: 'blur(10px)',
          border: `1px solid ${project.accentA}44`,
          borderRadius: 99, padding: '4px 11px',
          display: 'flex', alignItems: 'center', gap: 5,
        }}>
          <div style={{ width: 5, height: 5, borderRadius: '50%', background: project.accentA, boxShadow: `0 0 5px ${project.accentA}` }} />
          <span style={{ color: project.accentA, fontSize: 11, fontWeight: 700, letterSpacing: '0.05em' }}>
            AI {project.aiScore}
          </span>
        </div>
        {/* Category */}
        <div style={{
          position: 'absolute', top: 12, left: 12,
          background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(10px)',
          borderRadius: 99, padding: '4px 11px',
          fontSize: 10, color: '#9ca3af', letterSpacing: '0.1em', fontWeight: 600,
        }}>
          {project.category.toUpperCase()}
        </div>
        {/* Creator */}
        <div style={{
          position: 'absolute', bottom: 12, left: 12,
          display: 'flex', alignItems: 'center', gap: 7,
        }}>
          <div style={{
            width: 22, height: 22, borderRadius: '50%',
            background: project.accentA + '22',
            border: `1.5px solid ${project.accentA}`,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            fontSize: 8, fontWeight: 800, color: project.accentA,
          }}>
            {project.creator.split(' ').map(w => w[0]).join('')}
          </div>
          <span style={{ color: '#9ca3af', fontSize: 11, fontWeight: 500 }}>{project.creator}</span>
        </div>
      </div>

      {/* Body */}
      <div style={{ padding: '18px 20px', flex: 1, display: 'flex', flexDirection: 'column' }}>
        <h3 style={{
          fontFamily: 'Syne, sans-serif', fontSize: 16, fontWeight: 800,
          color: '#f9fafb', marginBottom: 6, lineHeight: 1.25,
        }}>
          {project.title}
        </h3>
        <p style={{ color: '#6b7280', fontSize: 12, lineHeight: 1.7, marginBottom: 16, flex: 1 }}>
          {project.desc}
        </p>

        {/* Progress */}
        <div style={{ marginBottom: 14 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 5 }}>
            <span style={{ color: '#f9fafb', fontSize: 13, fontWeight: 700 }}>
              ${project.raised.toLocaleString()}
            </span>
            <span style={{ color: '#374151', fontSize: 11 }}>
              of ${project.goal.toLocaleString()}
            </span>
          </div>
          <div style={{ background: '#1a2332', borderRadius: 99, height: 5, overflow: 'hidden' }}>
            <div style={{
              height: '100%', borderRadius: 99,
              background: `linear-gradient(90deg, ${project.accentA}, ${project.accentB})`,
              width: `${pct}%`,
              boxShadow: `0 0 8px ${project.accentA}77`,
            }} />
          </div>
          <div style={{ color: project.accentA, fontSize: 11, fontWeight: 700, marginTop: 4 }}>
            {pct}% funded
          </div>
        </div>

        {/* Footer */}
        <div style={{
          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
          paddingTop: 12, borderTop: '1px solid #1a2332',
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
            <div style={{ display: 'flex' }}>
              {project.avatarColors.map((c, i) => (
                <div key={i} style={{
                  width: 20, height: 20, borderRadius: '50%',
                  background: c + '28', border: `1.5px solid ${c}`,
                  marginLeft: i === 0 ? 0 : -6, zIndex: 3 - i,
                  display: 'flex', alignItems: 'center', justifyContent: 'center',
                  fontSize: 7, fontWeight: 800, color: c,
                }}>
                  {String.fromCharCode(65 + i)}
                </div>
              ))}
            </div>
            <span style={{ color: '#4b5563', fontSize: 11 }}>{project.backers.toLocaleString()} backers</span>
          </div>
          <span style={{
            color: '#ef4444', fontSize: 11, fontWeight: 600,
            background: 'rgba(239,68,68,0.08)', border: '1px solid rgba(239,68,68,0.2)',
            padding: '3px 9px', borderRadius: 99,
          }}>
            ⏱ {project.daysLeft}d left
          </span>
        </div>
      </div>
    </div>
  );
}

/* ── Scrolling live ticker ── */
const TICKER_ITEMS = [
  '🚀 NeuroSync just hit 85% funded', '⚡ SolarPack raised $12K today',
  '🎓 EduBot approved by AI', '💡 38 new projects this week',
  '🌱 Environment category trending', '🤖 Gemini scored 200+ projects',
  '🔥 Health Tech up 40% this month', '✅ 94% AI-approved projects succeed',
];

function Ticker() {
  const doubled = [...TICKER_ITEMS, ...TICKER_ITEMS];
  return (
    <div style={{
      borderTop: '1px solid #1f2937', borderBottom: '1px solid #1f2937',
      background: '#080b14', padding: '10px 0', overflow: 'hidden',
    }}>
      <style>{`@keyframes bsx-ticker { from { transform: translateX(0) } to { transform: translateX(-50%) } }`}</style>
      <div style={{ display: 'flex', whiteSpace: 'nowrap', animation: 'bsx-ticker 30s linear infinite' }}>
        {doubled.map((item, i) => (
          <span key={i} style={{ display: 'inline-flex', alignItems: 'center', gap: 0, paddingRight: 48 }}>
            <span style={{ color: '#4b5563', fontSize: 12 }}>{item}</span>
            <span style={{ color: '#1f2937', fontSize: 9, marginLeft: 48 }}>◆</span>
          </span>
        ))}
      </div>
    </div>
  );
}

/* ── Main page ── */
export default function Landing() {
  return (
    <div style={{ background: '#0a0d1a' }} className="min-h-screen">

      {/* Hero */}
      <section className="relative px-6 pt-28 pb-32 text-center overflow-hidden">
        <div style={{
          position: 'absolute', inset: 0, opacity: 0.15,
          background: 'radial-gradient(ellipse 80% 60% at 50% -20%, #00d4aa, transparent)'
        }} />
        <div className="relative max-w-4xl mx-auto">
          <div style={{ background: 'rgba(0,212,170,0.1)', border: '1px solid rgba(0,212,170,0.3)', color: '#00d4aa' }}
